deviceProfile.payloadCodecScript:
// Cole aqui o conteudo do seu codec JavaScript.
// Use templates/codecs/CODEC_TEMPLATE.js como ponto de partida.
// Exemplos: templates/codecs/example-actuator-bidirectional.js

function decodeUplink(input) {
  var bytes = input.bytes;
  if (bytes.length < 1) { return { data: {} }; }
  return { data: { raw: Array.from(bytes) } };
}

function encodeDownlink(input) {
  var data = input.data;
  return { bytes: [data.command || 0, data.value || 0] };
}

function decodeDownlink(input) {
  var bytes = input.bytes;
  if (bytes.length < 1) { return { data: {} }; }
  return { data: { command: bytes[0], value: bytes[1] || 0 } };
}
